[][130] +/**
[][131] + * @brief The server thread function
[][132] + *
[][133] + * This function simply accepts a client connection and
[][134] + * echoes the first @ref SECRET_SIZE bytes of the first
[][135] + * packet. After that, the server is closed and connections
[][136] + * are no longer accepted.
[][137] + *
[][138] + * @param arg0 a pointer to the int representing the server filed descriptor
[][139] + * @param arg1 ignored
[][140] + * @param arg2 ignored
[][141] + */
[][142] +static void server_thread_fn(void *arg0, void *arg1, void *arg2)
[][143] +{
[][144] +	const int server_fd = POINTER_TO_INT(arg0);
[][145] +
[][146] +	int r;
[][147] +	int client_fd;
[][148] +	socklen_t addrlen;
[][149] +	char addrstr[INET_ADDRSTRLEN];
[][150] +	struct sockaddr_in sa;
[][151] +	char *addrstrp;
[][152] +
[][153] +	k_thread_name_set(k_current_get(), "server");
[][154] +
[][155] +	NET_DBG("Server thread running");
[][156] +
[][157] +	memset(&sa, 0, sizeof(sa));
[][158] +	addrlen = sizeof(sa);
[][159] +
[][160] +	NET_DBG("Accepting client connection..");
[][161] +	k_sem_give(&server_sem);
[][162] +	r = accept(server_fd, (struct sockaddr *)&sa, &addrlen);
[][163] +	__ASSERT(r != -1, "accept() failed (%d)", r);
[][164] +	client_fd = r;
[][165] +
[][166] +	memset(addrstr, '\0', sizeof(addrstr));
[][167] +	addrstrp = (char *)inet_ntop(AF_INET, &sa.sin_addr,
[][168] +	addrstr, sizeof(addrstr));
[][169] +	__ASSERT(addrstrp != NULL, "inet_ntop() failed (%d)", errno);
[][170] +
[][171] +	NET_DBG("accepted connection from [%s]:%d as fd %d",
[][172] +	log_strdup(addrstr), ntohs(sa.sin_port), client_fd);
[][173] +
[][174] +	NET_DBG("calling recv()");
[][175] +	r = recv(client_fd, addrstr, sizeof(addrstr), 0);
[][176] +	__ASSERT(r != -1, "recv() failed (%d)", errno);
[][177] +	__ASSERT(r == SECRET_SIZE, "expected: %zu actual: %d", SECRET_SIZE, r);
[][178] +
[][179] +	NET_DBG("calling send()");
[][180] +	r = send(client_fd, SECRET, SECRET_SIZE, 0);
[][181] +	__ASSERT(r != -1, "send() failed (%d)", errno);
[][182] +	__ASSERT(r == SECRET_SIZE, "expected: %zu actual: %d", SECRET_SIZE, r);
[][183] +
[][184] +	NET_DBG("closing client fd");
[][185] +	r = close(client_fd);
[][186] +	__ASSERT(r != -1, "close() failed on the server fd (%d)", errno);
[][187] +}
