[][414] +void test_main(void)
[][415] +{
[][416] +	int r;
[][417] +	/*
[][418] +	 * Load both client & server credentials
[][419] +	 *
[][420] +	 * Normally, this would be split into separate applications but
[][421] +	 * for testing purposes, we just use separate threads.
[][422] +	 *
[][423] +	 * Also, it has to be done before tests are run, otherwise
[][424] +	 * there are errors due to attempts to load too many certificates.
[][425] +	 *
[][426] +	 * The server would normally load
[][427] +	 * - server public key
[][428] +	 * - server private key
[][429] +	 * - ca cert (only when client authentication is required)
[][430] +	 *
[][431] +	 * The client would normally load
[][432] +	 * - ca cert (to verify the server)
[][433] +	 * - client public key (only when client authentication is required)
[][434] +	 * - client private key (only when client authentication is required)
[][435] +	 */
